import java.util.Arrays;
import java.util.List;

public class PriorityBuilder {

    public void build(Candidate[] candidates, List<Candidate> target) {
        Arrays.sort(candidates, (a, b) -> Double.compare(b.getScore(), a.getScore()));
        for (Candidate c : candidates) {
            target.add(0, c);
        }
    }
}
